import{_ as o,c as r,o as s,ae as n}from"./chunks/framework.Cqi9LMMK.js";const d=JSON.parse('{"title":"Автозапуск","description":"","frontmatter":{"title":"Автозапуск"},"headers":[],"relativePath":"ru/options/auto_run.md","filePath":"ru/options/auto_run.md"}'),e={name:"ru/options/auto_run.md"};function a(i,t,l,g,u,p){return s(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="автозапуск-auto-run" tabindex="-1">Автозапуск (Auto Run) <a class="header-anchor" href="#автозапуск-auto-run" aria-label="Permalink to &quot;Автозапуск (Auto Run)&quot;">​</a></h1><blockquote><p><strong>Только режим расширения (Chrome / Edge).</strong> Блок <strong>Auto Run</strong> в <strong>Options → General</strong> не показывается в <strong>автономном (standalone)</strong> запуске: у закладки нет фонового процесса расширения, который решал бы, на каких вкладках автоматически показывать панель.</p></blockquote><p><strong>Auto Run</strong> задаёт, при каких сайтах в режиме <strong>оверлея</strong> на странице <strong>сама появляется</strong> компактная точка входа (pill) в инспектор. Это не то же самое, что чёрный список <strong>компонентов</strong> во вкладке Props — здесь речь только о <strong>адресах сайтов</strong> (origin: схема, хост, порт).</p><hr><h2 id="общая-логика" tabindex="-1">Общая логика <a class="header-anchor" href="#общая-логика" aria-label="Permalink to &quot;Общая логика&quot;">​</a></h2><p>Правила смотрят на <strong>origin</strong> открытой страницы (как в адресной строке, без пути). Можно указать полный URL вида <code>https://app.example/</code> или шаблон со звёздочками, например <code>*localhost*</code> — звёздочка означает «любой фрагмент». Пустые списки не ограничивают показ панели: ограничения включаются, когда в таблице есть записи (или включён режим белого списка, см. ниже).</p><p>Панель оверлея по-прежнему не появится на страницах, которые расширение считает <strong>статическими</strong> без Vue (отдельная проверка). От этого ограничения списки сайтов не освобождают — см. <strong>всплывающее окно</strong> расширения ниже.</p><hr><h2 id="site-blacklist-черныи-список-саитов" tabindex="-1">Site Blacklist (чёрный список сайтов) <a class="header-anchor" href="#site-blacklist-черныи-список-саитов" aria-label="Permalink to &quot;Site Blacklist (чёрный список сайтов)&quot;">​</a></h2><p>Таблица <strong>Site Blacklist</strong> — адреса и шаблоны, на которых <strong>автоматически не показывать</strong> точку входа в инспектор.</p><ul><li>Добавление: поле ввода и кнопка <strong>Add</strong> (или Enter).</li><li>В таблице видны <strong>шаблон</strong> и <strong>дата добавления</strong>; строку можно выбрать и отредактировать в боковой панели деталей.</li><li>Если текущий сайт <strong>совпал</strong> с любой записью из чёрного списка, автозапуск оверлея для этой вкладки отключается.</li></ul><p>Чёрный список <strong>можно комбинировать</strong> с белым: сначала проверяется белый список (если он активен и не пуст), затем чёрный.</p><hr><h2 id="site-whitelist-и-«whitelist-mode»" tabindex="-1">Site Whitelist и «whitelist mode» <a class="header-anchor" href="#site-whitelist-и-«whitelist-mode»" aria-label="Permalink to &quot;Site Whitelist и «whitelist mode»&quot;">​</a></h2><p>Переключатель <strong>Enable whitelist mode</strong> включает использование таблицы <strong>Site Whitelist</strong>.</p><ul><li>Пока <strong>белый список пуст</strong>, режим по сути никого не ограничивает: работают только правила <strong>чёрного</strong> списка (если он заполнен).</li><li>Как только в белом списке есть <strong>хотя бы одна</strong> запись, автоматический показ оверлея разрешён <strong>только</strong> на тех origins, которые <strong>совпали</strong> с одной из записей белого списка. Все остальные сайты для автозапуска считаются запрещёнными — до тех проверок, пока не сработает чёрный список поверх уже разрешённых.</li></ul><p>Иными словами: <strong>непустой белый список</strong> сужает круг «где можно», <strong>чёрный список</strong> вычитает из него отдельные адреса.</p><hr><h2 id="всплывающее-окно-расширения-popup-«запаснои-выход»" tabindex="-1">Всплывающее окно расширения (popup): «запасной выход» <a class="header-anchor" href="#всплывающее-окно-расширения-popup-«запаснои-выход»" aria-label="Permalink to &quot;Всплывающее окно расширения (popup): «запасной выход»&quot;">​</a></h2><p>У иконки Vue Inspector в панели браузера есть <strong>маленькое окно</strong> с двумя действиями (на английском в интерфейсе: <strong>Forced Launch</strong> и <strong>Reset Settings</strong>).</p><p><strong>Forced Launch</strong> — принудительно вставляет панель инспектора на <strong>текущей активной вкладке</strong>, <strong>игнорируя</strong> правила Auto Run (чёрный/белый список) и эвристику «статический сайт». Нужна, если вы сами настроили списки так, что pill больше нигде не появляется, а открыть <strong>Options</strong> неоткуда.</p><p><strong>Reset Settings</strong> — <strong>полный сброс</strong> сохранённых пользовательских настроек расширения (включая Auto Run, оформление, избранное и прочее). Это крайняя мера, если вы «перекрыли» себе доступ настройками: после сброса списки и режимы возвращаются к состоянию по умолчанию, и панель снова можно открыть обычным способом. Используйте осознанно: восстановить прежний профиль без резервной копии нельзя.</p><p>Совет: если пользуетесь жёстким белым списком, держите в нём хотя бы адрес страницы, с которой вы обычно заходите в Options, либо помните про <strong>Forced Launch</strong> и <strong>Reset Settings</strong> в popup.</p><hr><h2 id="см-также" tabindex="-1">См. также <a class="header-anchor" href="#см-также" aria-label="Permalink to &quot;См. также&quot;">​</a></h2><ul><li><a href="/docs/ru/guide/install.html#storage">Установка → Где хранятся настройки</a></li><li><a href="/docs/ru/guide/extension.html">Расширение браузера</a></li></ul>',26)])])}const c=o(e,[["render",a]]);export{d as __pageData,c as default};
